// Get the extracted business info from the AI agent
const extractedInfo = $input.first().json.output;

// Get the existing account memo (v1)
const existingMemo = $input.last().json;

// Helper function to merge objects, preferring new values if they exist
function mergeField(newValue, oldValue) {
  if (newValue !== undefined && newValue !== null && newValue !== '') {
    return newValue;
  }
  return oldValue;
}

// Build the updated account memo (v2)
const updatedMemo = {
  version: 'v2',
  updated_at: new Date().toISOString(),
  company_name: mergeField(extractedInfo.company_name, existingMemo.company_name),
  services_supported: extractedInfo.services_supported && extractedInfo.services_supported.length > 0 
    ? extractedInfo.services_supported 
    : existingMemo.services_supported || [],
  emergency_definition: mergeField(extractedInfo.emergency_definition, existingMemo.emergency_definition),
  business_hours: extractedInfo.business_hours && Object.keys(extractedInfo.business_hours).length > 0
    ? extractedInfo.business_hours
    : existingMemo.business_hours || {},
  routing_rules: extractedInfo.routing_rules && extractedInfo.routing_rules.length > 0
    ? extractedInfo.routing_rules
    : existingMemo.routing_rules || [],
  integration_constraints: extractedInfo.integration_constraints && extractedInfo.integration_constraints.length > 0
    ? extractedInfo.integration_constraints
    : existingMemo.integration_constraints || [],
  // Preserve any additional fields from the existing memo
  ...Object.keys(existingMemo)
    .filter(key => !['version', 'updated_at', 'company_name', 'services_supported', 'emergency_definition', 'business_hours', 'routing_rules', 'integration_constraints'].includes(key))
    .reduce((acc, key) => ({ ...acc, [key]: existingMemo[key] }), {})
};

return [{ json: updatedMemo }];

