// Get all input items (account_memo, agent_spec, changelog)
const items = $input.all();

// Define the expected filenames for each output
const filenames = ['account_memo.json', 'agent_spec.json', 'changelog.json'];

// Convert each JSON item to binary data
const binaryItems = items.map((item, index) => {
  const jsonData = item.json;
  const jsonString = JSON.stringify(jsonData, null, 2);
  const buffer = Buffer.from(jsonString, 'utf-8');

  return {
    json: {
      filename: filenames[index] || `output_${index}.json`
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: 'application/json',
        fileName: filenames[index] || `output_${index}.json`,
        fileExtension: 'json'
      }
    }
  };
});

return binaryItems;

